import { randomBytes, createCipheriv, createDecipheriv, scrypt } from 'crypto';
import { promisify } from 'util';
import { app } from 'electron';
import path from 'path';
import fs from 'fs';

const scryptAsync = promisify(scrypt);

/**
 * CredentialVault handles encryption and decryption of sensitive data
 * Uses AES-256-GCM with a key derived from a master password
 */
export class CredentialVault {
  private readonly algorithm = 'aes-256-gcm';
  private readonly saltLength = 32;
  private readonly ivLength = 16;
  private readonly keyLength = 32;
  private readonly tagLength = 16;

  private masterKey: Buffer | null = null;

  constructor() {
    this.initializeMasterKey();
  }

  /**
   * Initialize or load the master key
   * In production, this should use the OS keychain (Keychain Access on macOS, Credential Manager on Windows)
   * For MVP, we'll use a file-based approach with a randomly generated key
   */
  private initializeMasterKey() {
    const userDataPath = app.getPath('userData');
    const keyPath = path.join(userDataPath, '.vault_key');

    try {
      if (fs.existsSync(keyPath)) {
        // Load existing key
        this.masterKey = fs.readFileSync(keyPath);
      } else {
        // Generate new key
        this.masterKey = randomBytes(this.keyLength);
        fs.writeFileSync(keyPath, this.masterKey, { mode: 0o600 });
        console.log('Generated new vault master key');
      }
    } catch (error) {
      console.error('Error initializing master key:', error);
      throw new Error('Failed to initialize credential vault');
    }
  }

  /**
   * Encrypt a secret string
   */
  async encrypt(plaintext: string): Promise<Buffer> {
    if (!this.masterKey) {
      throw new Error('Vault not initialized');
    }

    try {
      // Generate a random salt for this encryption
      const salt = randomBytes(this.saltLength);

      // Derive encryption key from master key and salt
      const key = (await scryptAsync(this.masterKey, salt, this.keyLength)) as Buffer;

      // Generate random IV
      const iv = randomBytes(this.ivLength);

      // Create cipher
      const cipher = createCipheriv(this.algorithm, key, iv);

      // Encrypt
      const encrypted = Buffer.concat([
        cipher.update(plaintext, 'utf8'),
        cipher.final(),
      ]);

      // Get auth tag
      const tag = cipher.getAuthTag();

      // Combine salt + iv + tag + encrypted data
      return Buffer.concat([salt, iv, tag, encrypted]);
    } catch (error) {
      console.error('Encryption error:', error);
      throw new Error('Failed to encrypt secret');
    }
  }

  /**
   * Decrypt a secret
   */
  async decrypt(encryptedData: Buffer): Promise<string> {
    if (!this.masterKey) {
      throw new Error('Vault not initialized');
    }

    try {
      // Extract salt, iv, tag, and encrypted data
      const salt = encryptedData.subarray(0, this.saltLength);
      const iv = encryptedData.subarray(
        this.saltLength,
        this.saltLength + this.ivLength
      );
      const tag = encryptedData.subarray(
        this.saltLength + this.ivLength,
        this.saltLength + this.ivLength + this.tagLength
      );
      const encrypted = encryptedData.subarray(
        this.saltLength + this.ivLength + this.tagLength
      );

      // Derive decryption key
      const key = (await scryptAsync(this.masterKey, salt, this.keyLength)) as Buffer;

      // Create decipher
      const decipher = createDecipheriv(this.algorithm, key, iv);
      decipher.setAuthTag(tag);

      // Decrypt
      const decrypted = Buffer.concat([
        decipher.update(encrypted),
        decipher.final(),
      ]);

      return decrypted.toString('utf8');
    } catch (error) {
      console.error('Decryption error:', error);
      throw new Error('Failed to decrypt secret');
    }
  }

  /**
   * Re-encrypt all secrets with a new master key
   * Useful for key rotation
   */
  async rotateKey(newMasterKey: Buffer): Promise<void> {
    const oldKey = this.masterKey;
    this.masterKey = newMasterKey;

    const userDataPath = app.getPath('userData');
    const keyPath = path.join(userDataPath, '.vault_key');

    try {
      fs.writeFileSync(keyPath, newMasterKey, { mode: 0o600 });
      console.log('Master key rotated successfully');
    } catch (error) {
      // Rollback on failure
      this.masterKey = oldKey;
      throw new Error('Failed to rotate master key');
    }
  }
}
